def find_hamiltonian_path(graph):
    num_vertices = len(graph)

    def hamiltonian_path_recursive(current_path, visited_nodes):
        if len(current_path) == num_vertices:
            return True

        last_vertex = current_path[-1]

        for neighbor in graph[last_vertex]:
            if neighbor not in visited_nodes:
                current_path.append(neighbor)
                visited_nodes.add(neighbor)

                if hamiltonian_path_recursive(current_path, visited_nodes):
                    return True

                visited_nodes.remove(neighbor)
                current_path.pop()

        return False

    for start_node in graph.keys():
        initial_path = [start_node]
        initial_visited = {start_node}

        if hamiltonian_path_recursive(initial_path, initial_visited):
            return initial_path

    return None
